import React from 'react';
import './App.css';

function App() {
  const handleClick = (section) => {
    alert(`מעבר אל: ${section}`);
  };

  const runEncryption = async () => {
    const folderPath = prompt("📁 הכנס נתיב תיקייה (יחסי לשרת):", "./target");
    if (!folderPath) return;

    try {
      const response = await fetch("http://127.0.0.1:5000/encrypt", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ folder: folderPath })
      });

      const result = await response.json();
      alert(`✅ סטטוס: ${result.status}\n📁 תיקייה: ${result.folder}`);
    } catch (error) {
      alert("❌ שגיאה בחיבור לשרת");
    }
  };

  return (
    <div className="App">
      <h1 className="title">לומדת סימולציות Ransomware – <span style={{ color: "#ff1744" }}>ByteMe 🧠</span></h1>
      <div className="menu">
        <button onClick={() => handleClick("תיאוריה כללית")}>📘 תיאוריה כללית</button>
        <button onClick={runEncryption}>💣 הפעל הצפנה</button>
        <button onClick={() => handleClick("תרגול מעשי")}>🧪 תרגול מעשי</button>
        <button onClick={() => handleClick("כלים נוספים")}>🛠 כלים נוספים</button>
        <button onClick={() => handleClick("סיכום")}>📊 סיכום וסטטיסטיקות</button>
      </div>
    </div>
  );
}

export default App;
